/// {@category Containers}
library;

// Dart imports:
import 'dart:async';

// Flutter imports:
import 'package:flutter/material.dart';

// Package imports:
import 'package:flutter_hooks/flutter_hooks.dart';
import 'package:gap/gap.dart';
import 'package:hooks_riverpod/hooks_riverpod.dart';

// Project imports:
import 'package:baseball_detector_flutter/l10n/l10n_ext.dart';
import 'package:baseball_detector_flutter/providers/profile_storage_provider.dart';
import 'package:baseball_detector_flutter/views/components/custom_app_bar.dart';
import 'package:baseball_detector_flutter/views/components/custom_text_form_field.dart';
import 'package:baseball_detector_flutter/views/components/edit_page_layout.dart';
import 'package:baseball_detector_flutter/views/hooks/use_single_action.dart';
import 'package:baseball_detector_flutter/views/pages/sign_up/confirm_code/hooks/use_auth_code_operations.dart';
import 'package:baseball_detector_flutter/views/themes/font_manager.dart';

class ConfirmCodePage extends HookConsumerWidget {
  const ConfirmCodePage({super.key});

  @override
  Widget build(BuildContext context, WidgetRef ref) {
    final codeController = useTextEditingController();
    final isLoading = useState(false);
    final errorMessage = useState<String?>(null);
    final authCodeOperations = useAuthCodeOperations();

    // Resend email tracking
    final resendCount = useState(0);
    final canResend = useState(true);
    final remainingSeconds = useState(0);
    final timerRef = useRef<Timer?>(null);

    // Cancel timer on dispose
    useEffect(() {
      return () {
        timerRef.value?.cancel();
      };
    }, []);

    final email = useFuture(
      useMemoized(() => ref.read(profileStorageProvider).getEmail()),
    );

    Future<void> validateAndSubmit() async {
      if (codeController.text.trim().isEmpty) {
        errorMessage.value = context.l10n.confirm_code_page__code_required;
        return;
      }

      isLoading.value = true;
      errorMessage.value = null;

      final result = await authCodeOperations.confirmCode(codeController.text);
      if (!result && context.mounted) {
        codeController.text = '';
      }

      isLoading.value = false;
    }

    Future<void> resendCode() async {
      if (isLoading.value || !canResend.value) return;

      isLoading.value = true;
      await authCodeOperations.resendCode();
      isLoading.value = false;

      // Update resend count and set cooldown
      resendCount.value++;
      canResend.value = false;

      // Set cooldown duration: 1 minute for first resend, 5 minutes for subsequent
      final cooldownSeconds = resendCount.value == 1 ? 60 : 300;
      remainingSeconds.value = cooldownSeconds;

      // Cancel any existing timer
      timerRef.value?.cancel();

      // Start countdown timer
      timerRef.value = Timer.periodic(const Duration(seconds: 1), (timer) {
        if (!context.mounted) {
          timer.cancel();
          return;
        }

        if (remainingSeconds.value > 0) {
          remainingSeconds.value--;
        } else {
          timer.cancel();
          canResend.value = true;
          timerRef.value = null;
        }
      });
    }

    // 多重送信/再送防止
    final runValidate = useSingleAction<void>(asyncCallback: (_) async {
      await validateAndSubmit();
    });
    final runResend = useSingleAction<void>(asyncCallback: (_) async {
      await resendCode();
    });

    return Scaffold(
      appBar: CustomAppBar(
        title: context.l10n.confirm_code_page__title,
        isBackNavigation: true,
      ),
      body: SafeArea(
        child: EditPageLayout(
          buttonText: context.l10n.confirm_code_page__next,
          onPressed: runValidate,
          loading: isLoading.value,
          children: [
            const Gap(8),
            Text(
              context.l10n.confirm_code_page__description(
                email.hasData ? email.data ?? '' : '',
              ),
              style: Theme.of(context).textTheme.bodyMedium,
            ),
            const Gap(24),
            CustomTextFormField(
              controller: codeController,
              label: Text(context.l10n.confirm_code_page__code_label),
              keyboardType: TextInputType.number,
              errorText: errorMessage.value,
              maxLength: 6,
              onChanged: (value) {
                errorMessage.value = null;
              },
            ),
            const Gap(24),
            GestureDetector(
              onTap: canResend.value ? runResend : null,
              child: Text(
                canResend.value
                    ? context.l10n.confirm_code_page__not_received
                    : _formatResendText(context, remainingSeconds.value),
                style: canResend.value
                    ? TextStyleManager.link
                    : TextStyleManager.link.copyWith(
                        color: Theme.of(context).disabledColor,
                      ),
              ),
            ),
          ],
        ),
      ),
    );
  }

  String _formatResendText(BuildContext context, int seconds) {
    final minutes = seconds ~/ 60;
    final remainingSeconds = seconds % 60;
    return context.l10n.confirm_code_page__resend_cooldown(
      ' $minutes:${remainingSeconds.toString().padLeft(2, '0')} ',
    );
  }
}

